  ('Eccentric Heel Drop (Bilateral, Off Step)', 'eccentric-heel-drop-bilateral-off-step', 'rehab', NULL, 'Rise on both feet, shift to the working leg, lower the heel slowly BELOW the step over ~3s. Alfredson-style eccentric loading; pain up to 5/10 that settles overnight is acceptable.', 'Rise on both feet, shift to the working leg, lower the heel slowly BELOW the step over ~3s. Alfredson-style eccentric loading; pain up to 5/10 that settles overnight is acceptable.', ARRAY['Lower slowly below the step','Rise with both, lower with one','Pain ≤5/10 that settles by morning is OK'], ARRAY['calves'], ARRAY['gastrocnemius','soleus'], 'Eccentric Plantarflexion', '{}', FALSE, 12, 3, 15, NULL, NULL, 'beginner', '{}', TRUE, ARRAY['gastrocnemius','achilles'], 'eccentric', 'knee_straight', 'low', 3, 'RCT', 2),
